// V47.3 Supabase-First: fetch cost directly from Supabase, bypass Airtable Rate Limit
// Fallback: Airtable path (V47.2 delay) if Supabase unavailable
const SUPABASE_URL = 'https://vpmwizzixnwilmzctdvu.supabase.co';
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY
  || 'sb_secret_EXq938yU-MinIxdpOc0nZg_qL-N3BCq';

const batchItems = $("Batch SKU Collector").all();
const hasValidItems = batchItems.some(item => item.json.hasItems === true);
const skuList = batchItems.length > 0 ? (batchItems[0].json.sku_list || []) : [];

if (hasValidItems && skuList.length > 0) {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/rpc/get_base_cost_by_skus`, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ sku_list: skuList })
    });

    if (res.ok) {
      const costRows = await res.json();
      if (Array.isArray(costRows) && costRows.length > 0) {
        // Build cost map keyed by Product_Name (matches Local Data Mapper lookup key)
        const supabaseCosts = {};
        costRows.forEach(r => { supabaseCosts[r.Product_Name] = r; });

        // Override batchFormula to SKIP Airtable lookup (returns 0 records, no error)
        // Airtable node still runs (n8n requires it) but returns empty safely
        return batchItems.map(item => ({
          json: {
            ...item.json,
            useCache: false,
            supabaseFetched: true,
            supabaseCosts,
            batchFormula: "RECORD_ID()='SUPABASE_SKIP'"
          }
        }));
      }
    }
  } catch (e) {
    // Supabase unreachable — fall through to Airtable
  }
}

// Airtable fallback (V47.2 rate-limit delay still active)
if (hasValidItems) {
  await new Promise(r => setTimeout(r, 250));
}
return batchItems.map(item => ({
  json: { ...item.json, useCache: false, supabaseFetched: false }
}));
